```tsx
import React, { useState, useEffect } from 'react';
import { View, Button, Text, StyleSheet } from 'react-native';
import MapView, { Marker } from 'react-native-maps';
import * as Location from 'expo-location';

const AddressPicker = ({ onAddressSelected }) => {
  const [region, setRegion] = useState(null);
  const [address, setAddress] = useState(null);
  const [markerCoord, setMarkerCoord] = useState(null);

  useEffect(() => {
    (async () => {
      let { status } = await Location.requestForegroundPermissionsAsync();
      if (status !== 'granted') return;
      let location = await Location.getCurrentPositionAsync({});
      const initialCoord = {
        latitude: location.coords.latitude,
        longitude: location.coords.longitude,
      };
      setMarkerCoord(initialCoord);
      setRegion({
        ...initialCoord,
        latitudeDelta: 0.01,
        longitudeDelta: 0.01,
      });
      await reverseGeocode(initialCoord);
    })();
  }, []);

  const reverseGeocode = async (coord) => {
    const results = await Location.reverseGeocodeAsync(coord);
    if (results.length > 0) {
      const addr = results[0];
      setAddress(`${addr.street} ${addr.streetNumber}, ${addr.postalCode} ${addr.city}`);
    }
  };

  const onMarkerDragEnd = async (e) => {
    const newCoord = e.nativeEvent.coordinate;
    setMarkerCoord(newCoord);
    await reverseGeocode(newCoord);
  };

  const handleValidate = () => {
    if (markerCoord && address) {
      onAddressSelected({ ...markerCoord, address });
    }
  };

  if (!region) return <Text>Chargement...</Text>;

  return (
    <View style={styles.container}>
      <MapView
        style={styles.map}
        region={region}
        onRegionChangeComplete={setRegion}
      >
        <Marker
          coordinate={markerCoord}
          draggable
          onDragEnd={onMarkerDragEnd}
          title="Livraison ici"
        />
      </MapView>
      {address && (
        <View style={styles.addressCard}>
          <Text>Adresse sélectionnée : {address}</Text>
          <Button title="Valider cette adresse" onPress={handleValidate} />
        </View>
      )}
    </View>
  );
};

const styles = StyleSheet.create({
  container: { flex: 1 },
  map: { flex: 1 },
  addressCard: { position: 'absolute', bottom: 20, left: 20, right: 20, backgroundColor: 'white', padding: 16, borderRadius: 12, elevation: 5 },
});
